-0.05958458,-0.04972559,0.04061412,0.03441592,0.00220528,0.05285776,0.01203088,0.00150594,-0.01623660,-0.01683830,-0.08229974,-0.03642102,0.05582976,-0.01085781,-0.02861294,-0.01681799,-0.08950362,-0.03197006,-0.02484837,0.05097511,0.03556815,0.03527454,-0.08772568,-0.03486618,-0.07287189,-0.01863980,0.04402192,-0.00288076,-0.04233294,0.02083957,-0.07112959,0.04220708,0.08204604,0.03704121,-0.02210692,0.00136101,-0.05283633,0.00836273,-0.03350629,0.14687951,0.05248483,0.10891496]',E'Docker-based Tests\n\n```go\nfunc TestStandardPerfReplication_Docker(t *testing.T) {\n  opts := docker.DefaultOptions(t)\n  r, err := docker.NewReplicationSetDocker(t, opts)\n  if err != nil {\n      t.Fatal(err)\n  }\n  defer r.Cleanup()\n\n  ctx, cancel := context.WithTimeout(context.Background(), time.Minute)\n  defer cancel()\n  err = r.StandardPerfReplication(ctx)\n  if err != nil {\n    t.Fatal(err)\n  }\n}','{"source": "vault", "version": "1.17", "language": "hcl", "title": "Vault [![build](https://github.com/hashicorp/vault/actions/workflows/build.yml/badge.svg)](https://github.com/hashicorp/vault/actions/workflows/build.yml) [![ci](https://github.com/hashicorp/vault/actions/workflows/ci.yml/badge.svg)](https://github.com/hashicorp/vault/actions/workflows/ci.yml)  [![vault enterprise](https://img.shields.io/badge/vault-enterprise-yellow.svg?colorB=7c8797&colorA=000000)](https://www.hashicorp.com/products/vault/?utm_source=github&utm_medium=banner&utm_campaign=github-vault-enterprise)", "section_title": "README", "url": "https://github.com/hashicorp/vault/blob/main/README.md", "topics": "vault,secrets,security,README", "categories": "devops,security,secrets"}');
